{
  "global": "Navigate the fashion e-commerce website, locate a baby one piece garment, and add exactly one unit to the shopping cart.",
  "subtasks": [
    {
      "subtask": "Browse to baby clothing section and search for one piece items",
      "atomics": [
        "Load the fashion retailer's website",
        "Navigate to the baby or infant clothing category",
        "Filter or search for 'one piece' clothing items",
        "Identify available baby one piece products in search results"
      ]
    },
    {
      "subtask": "View and configure the selected baby one piece product",
      "atomics": [
        "Click on a baby one piece product to open the product detail page",
        "Review product specifications including available sizes and colors",
        "Select the desired size and color options from dropdown menus or radio buttons"
      ]
    },
    {
      "subtask": "Add the product to the shopping cart",
      "atomics": [
        "Verify the quantity field is set to 1",
        "Click the 'Add to Cart' button",
        "Wait for and confirm the add-to-cart success message or notification"
      ]
    }
  ],
  "global_atomics": [
    "Verify the website homepage loads without errors",
    "Confirm the shopping cart displays one baby one piece item with correct product name and quantity"
  ],
  "gold_actions": {
    "global": "Interact with an e-commerce website to complete the task of adding one baby one piece garment to the shopping cart.",
    "subtasks": [
      {
        "subtask": "Access the baby clothing category and locate one piece items",
        "atomics": [
          "Load the website and dismiss any popups or overlays",
          "Click the Baby or Infant section link in the main navigation",
          "Apply a filter for One Piece or Romper clothing type",
          "Examine the product grid or list for baby one piece options"
        ]
      },
      {
        "subtask": "Open a baby one piece product and select size/color options",
        "atomics": [
          "Click on the first available baby one piece product card or image",
          "Extract the product name and price from the detail page",
          "Select a size from the size dropdown (e.g., 3M, 6M, 12M)",
          "Select a color from the color selector if multiple options exist"
        ]
      },
      {
        "subtask": "Add the configured product to the shopping cart",
        "atomics": [
          "Locate the quantity input field and ensure it reads 1",
          "Click the 'Add to Cart' button on the product detail page",
          "Poll the page or wait for the cart icon to update with the new item count"
        ]
      }
    ],
    "global_atomics": [
      "Check that the website is fully loaded and all navigation elements are clickable",
      "Verify the cart badge or mini-cart displays a count of 1 item after the add action"
    ]
  }
}
